import { useState, useEffect } from "react";
import { api, getAuthToken } from "../api";
import MedicineCard from "../components/MedicineCard";

export default function Search() {
  const [query, setQuery] = useState("");
  const [meds, setMeds] = useState([]);
  const [error, setError] = useState("");
  const [message, setMessage] = useState("");
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);

  useEffect(() => {
    search();
  }, [page]);

  const search = async (newPage = 1) => {
    if (!getAuthToken()) {
      setError("Please login first.");
      setMeds([]);
      return;
    }

    try {
      setError("");
      setMessage("");
      const params = { page: newPage };
      if (query) {
        params.q = query;
      }
      const res = await api.get("/medicines/", { params });
      
      const medicines = res.data.results || res.data;
      const total = res.data.count ? Math.ceil(res.data.count / 8) : 1;
      
      setMeds(medicines);
      setTotalPages(total);
      setPage(newPage);
    } catch (err) {
      setError("Unable to fetch medicines. Please login and try again.");
      setMeds([]);
    }
  };

  const addToCart = async (medicineId) => {
    try {
      setError("");
      await api.post("/cart/", { medicine: medicineId, quantity: 1 });
      setMessage("✓ Added to cart successfully!");
      setTimeout(() => setMessage(""), 3000);
    } catch (err) {
      setError(err.response?.data?.detail || "Unable to add to cart.");
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    search(1);
  };

  return (
    <div className="page">
      <section className="search-hero">
        <div className="page-header">
          <h1>🔍 Discover Medicines</h1>
          <p>Browse and order quality medicines</p>
        </div>

        <form onSubmit={handleSearch} className="search-container">
          <div className="search-box">
            <input
              type="text"
              placeholder="Search medicine, shop, area, or state"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              className="search-input"
            />
            <button type="submit" className="btn-search" aria-label="Search medicines">
              🔍
            </button>
          </div>
        </form>
      </section>

      {error && <div className="error-message">{error}</div>}
      {message && <div className="success-message">{message}</div>}

      {meds.length > 0 ? (
        <>
          <div className="results-info">
            Found {meds.length} medicine(s) • Page {page} of {totalPages}
          </div>

          <div className="medicine-grid">
            {meds.map((m) => (
              <MedicineCard 
                key={m.id}
                medicine={m}
                onAddToCart={addToCart}
              />
            ))}
          </div>

          {totalPages > 1 && (
            <div className="pagination-row">
              <button 
                onClick={() => search(page - 1)} 
                disabled={page === 1}
                className="btn-pagination"
              >
                ← Previous
              </button>
              
              <div className="pagination-info">
                Page {page} of {totalPages}
              </div>
              
              <button 
                onClick={() => search(page + 1)} 
                disabled={page === totalPages}
                className="btn-pagination"
              >
                Next →
              </button>
            </div>
          )}
        </>
      ) : (
        !error && (
          <div className="empty-state">
            <div className="empty-icon">💊</div>
            <h3>No medicines found</h3>
            <p>Try searching for different medicine names</p>
          </div>
        )
      )}
    </div>
  );
}
